// Determinar URL de API segun tipo de fuente
const source = $input.first().json;
let apiUrl = '';
let params = {};

switch (source.source_type) {
  case 'youtube_channel':
    // YouTube Data API v3 — buscar videos nuevos del canal
    apiUrl = 'https://www.googleapis.com/youtube/v3/search';
    params = {
      part: 'snippet',
      channelId: source.source_identifier,
      order: 'date',
      maxResults: 5,
      type: 'video',
      publishedAfter: source.last_checked_at || new Date(Date.now() - 7 * 24 * 60 * 60 * 1000).toISOString()
    };
    break;
  case 'youtube_playlist':
    apiUrl = 'https://www.googleapis.com/youtube/v3/playlistItems';
    params = {
      part: 'snippet',
      playlistId: source.source_identifier,
      maxResults: 5
    };
    break;
  case 'blog_rss':
  case 'podcast_rss':
    apiUrl = source.source_url; // RSS feed URL directa
    break;
}

return [{ json: { ...source, api_url: apiUrl, api_params: params } }];

// Extraer contenido nuevo y preparar para Gemini
const source = $('Build API URL').first().json;
const response = $input.first().json;
let items = [];

if (source.source_type.startsWith('youtube')) {
  const videos = response.items || [];
  items = videos
    .filter(v => v.id.videoId !== source.last_content_id)
    .map(v => ({
      id: v.id.videoId || v.snippet.resourceId?.videoId,
      title: v.snippet.title,
      description: v.snippet.description,
      url: 'https://youtube.com/watch?v=' + (v.id.videoId || v.snippet.resourceId?.videoId),
      type: 'youtube_video'
    }));
} else {
  // RSS parsing — simplified, real implementation would use xml parser
  items = [{
    id: 'rss-' + Date.now(),
    title: response.title || 'New content',
    description: response.description || '',
    url: source.source_url,
    type: source.source_type
  }];
}

if (items.length === 0) {
  return [{ json: { no_new_content: true, source_id: source.id } }];
}

return items.map(item => ({ json: { ...item, source } }));

// Parsear respuesta de Gemini y crear entradas en content_queue
const response = $input.first().json;
const contentItem = $('Has New Content?').first().json;
const source = contentItem.source;

let repurposed;
try {
  const text = response.candidates[0].content.parts[0].text;
  repurposed = JSON.parse(text);
} catch (e) {
  const text = response.candidates[0].content.parts[0].text;
  const match = text.match(/\{.*\}/s);
  repurposed = match ? JSON.parse(match[0]) : null;
}

if (!repurposed) {
  return [{ json: { error: 'Failed to parse Gemini response' } }];
}

const outputPlatforms = source.output_platforms || ['facebook', 'instagram', 'x', 'linkedin'];
const queueItems = [];

// LinkedIn article
if (outputPlatforms.includes('linkedin') && repurposed.linkedin) {
  queueItems.push({
    source_id: source.id,
    client_id: source.client_id,
    original_url: contentItem.url,
    original_title: contentItem.title,
    original_type: contentItem.type,
    platform: 'linkedin',
    caption: repurposed.linkedin,
    image_prompt: repurposed.image_prompt
  });
}

// X posts (multiple)
if (outputPlatforms.includes('x') && repurposed.x_posts) {
  repurposed.x_posts.forEach(tweet => {
    queueItems.push({
      source_id: source.id,
      client_id: source.client_id,
      original_url: contentItem.url,
      original_title: contentItem.title,
      original_type: contentItem.type,
      platform: 'x',
      caption: tweet,
      image_prompt: repurposed.image_prompt
    });
  });
}

// Instagram
if (outputPlatforms.includes('instagram') && repurposed.instagram) {
  queueItems.push({
    source_id: source.id,
    client_id: source.client_id,
    original_url: contentItem.url,
    original_title: contentItem.title,
    original_type: contentItem.type,
    platform: 'instagram',
    caption: repurposed.instagram,
    image_prompt: repurposed.image_prompt
  });
}

// Facebook
if (outputPlatforms.includes('facebook') && repurposed.facebook) {
  queueItems.push({
    source_id: source.id,
    client_id: source.client_id,
    original_url: contentItem.url,
    original_title: contentItem.title,
    original_type: contentItem.type,
    platform: 'facebook',
    caption: repurposed.facebook,
    image_prompt: repurposed.image_prompt
  });
}

return queueItems.map(item => ({ json: item }));
